#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 1000
#define MAXQ 10000

int T, N, Q, V, M, A, B;
int graph[MAXN][MAXN];
int visited[MAXN];
int distance[MAXN];

void bfs(int start) {
    for (int i = 0; i < N; i++) {
        visited[i] = 0;
        distance[i] = -1;
    }
    distance[start] = 0;
    visited[start] = 1;
    int queue[N];
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < N; v++) {
            if (graph[u][v] && !visited[v]) {
                visited[v] = 1;
                distance[v] = distance[u] + 1;
                queue[rear++] = v;
            }
        }
    }
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf(" %c", &graph[i][j]);
                graph[i][j] -= '0';
            }
        }
        scanf("%d", &Q);
        while (Q--) {
            scanf("%d %d", &V, &M);
            V--;
            for (int i = 0; i < M; i++) {
                scanf("%d %d", &A, &B);
                A--; B--;
                graph[A][B] ^= 1;
            }
            bfs(V);
            int sum = 0;
            for (int i = 0; i < N; i++) {
                if (distance[i] != -1) {
                    sum += distance[i];
                }
            }
            printf("%d\n", sum);
        }
    }
    return 0;
}

